module RefModule(  
    input [47:0] dest_mac,    // Destination MAC address from Ethernet frame  
    input [47:0] filter_mac,  // Filter MAC address  
    output reg match          // Match signal  
);  
  wire [47:0] _tap_dest_mac = dest_mac & {48{1'b1}};

    always @(*) begin  
        if(dest_mac == filter_mac)  
            match = 1'b1;  
        else  
            match = 1'b0;  
    end  
endmodule
